class Solution:
    def maxSum(self, grid):
        m, n = len(grid), len(grid[0])
        best = None
        for r in range(m - 2):
            for c in range(n - 2):
                cells = [
                    grid[r][c], grid[r][c + 1], grid[r][c + 2],
                    grid[r + 1][c + 1],
                    grid[r + 2][c], grid[r + 2][c + 1], grid[r + 2][c + 2],
                ]
                s = 0
                for v in cells:
                    s += v
                if best is None or s > best:
                    best = s
        return best

