var maxSum = function(grid) {
    const m = grid.length, n = grid[0].length;
    let best = -1;
    for (let r = 0; r <= m - 3; r++) {
        for (let c = 0; c <= n - 3; c++) {
            const top = grid[r][c] + grid[r][c + 1] + grid[r][c + 2];
            const mid = grid[r + 1][c + 1];
            const bot = grid[r + 2][c] + grid[r + 2][c + 1] + grid[r + 2][c + 2];
            const total = top + mid + bot;
            if (total > best) best = total;
        }
    }
    return best;
};
